INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '57e948ae-5a57-4273-a815-9a73e8fae8b2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Viem: Unlocking Blockchain Events with The Graph and Subgraphs$escape$,
  $escape$The Graph is a powerful tool for indexing blockchain events, enabling efficient querying via GraphQL. In viem, you can leverage The Graph's hosted service or run a decentralized node. To get started, define a subgraph using the Graph Protocol's schema language, then deploy it to a hosted service like The Graph Hosted Service or a decentralized network. In viem, use the `@graphprotocol/graph-cli` package to scaffold and deploy your subgraph. Once deployed, query your subgraph using GraphQL, taking advantage of viem's built-in support for GraphQL queries.$escape$,
  $escape$const { GraphCLI } = require('@graphprotocol/graph-cli');
const graphCLI = new GraphCLI();
graphCLI.init().then(() => {
  graphCLI.deploy('my-subgraph');
});$escape$,
  $escape$javascript$escape$,
